import{_ as n}from"./chunks/alink_window.BEamZtgc.js";import{c as i,Q as e,j as s,m as t}from"./chunks/framework.rlpw0eGz.js";const m=JSON.parse('{"title":"Встановлення Adaptive-Link OpenIPC","description":"Детальна інструкція з налаштування Adaptive-Link","frontmatter":{"title":"Встановлення Adaptive-Link OpenIPC","description":"Детальна інструкція з налаштування Adaptive-Link","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/configuration/adaptive-link"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/configuration/adaptive-link"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/configuration/adaptive-link"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/configuration/adaptive-link"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/configuration/adaptive-link"}],["meta",{"property":"og:title","content":"Встановлення Adaptive-Link OpenIPC"}],["meta",{"property":"og:description","content":"Детальна інструкція з налаштування Adaptive-Link"}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-config.png"}],["meta",{"property":"og:locale","content":"uk_UA"}],["meta",{"property":"og:locale:alternate","content":"en_US"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-config.png"}],["meta",{"name":"twitter:title","content":"Встановлення Adaptive-Link OpenIPC"}],["meta",{"name":"twitter:description","content":"Детальна інструкція з налаштування Adaptive-Link"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Головна\\",\\"item\\":\\"https://openfpv.com.ua/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Конфігурація\\",\\"item\\":\\"https://openfpv.com.ua/configuration/multiconfigurator\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Встановлення Adaptive-Link OpenIPC\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Встановлення Adaptive-Link OpenIPC\\",\\"description\\":\\"Детальна інструкція з налаштування Adaptive-Link\\",\\"inLanguage\\":\\"uk-UA\\",\\"url\\":\\"https://openfpv.com.ua/configuration/adaptive-link\\",\\"image\\":\\"https://openfpv.com.ua/og-config.png\\",\\"dateModified\\":\\"2026-05-31T11:48:56.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"configuration/adaptive-link.md","filePath":"configuration/adaptive-link.md","lastUpdated":1780228136000}'),l={name:"configuration/adaptive-link.md"};function p(o,a,r,c,d,h){return e(),s("div",null,[...a[0]||(a[0]=[t(`<h2 id="що-таке-adaptive-link" tabindex="-1">Що таке Adaptive-Link? <a class="header-anchor" href="#що-таке-adaptive-link" aria-label="Permalink to &quot;Що таке Adaptive-Link?&quot;">​</a></h2><p><strong>Adaptive-Link</strong> — це система, яка <strong>автоматично перемикає якість відео та зв’язку</strong> між дроном і наземною станцією залежно від сили сигналу.</p><blockquote><p>Коли ви близько — відео чітке й плавне.<br> Коли далеко — якість зменшується, але зв’язок залишається стабільним.</p></blockquote><div class="info custom-block"><p class="custom-block-title">Інфо</p><p>Тобто, як раніше вручну виставляти потужність більше не потрібно!</p></div><hr><h2 id="як-це-працює" tabindex="-1">Як це працює? <a class="header-anchor" href="#як-це-працює" aria-label="Permalink to &quot;Як це працює?&quot;">​</a></h2><p><strong>Adaptive-Link</strong> автоматично контролює:</p><ul><li>Bitrate</li><li>Потужність передавача</li><li>Параметри MCS, SNR, RSSI</li><li>FEC та QoS залежно від відстані та умов</li></ul><hr><h2 id="встановлення-adaptive-link-на-radxa-gs" tabindex="-1">Встановлення Adaptive-Link на Radxa GS <a class="header-anchor" href="#встановлення-adaptive-link-на-radxa-gs" aria-label="Permalink to &quot;Встановлення Adaptive-Link на Radxa GS&quot;">​</a></h2><ol><li>Образ v1.9.9 або новіший → відключити живлення Wi-Fi карток.</li><li>Перезавантажити Radxa і зайти як <code>radxa/radxa</code> або <code>root/root</code>.</li><li>Виконати <code>nmtui</code> — підключитися до домашнього Wi-Fi.</li><li>SSH → виконати:</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo curl -L -o alink_install.sh https://raw.githubusercontent.com/OpenIPC/adaptive-link/refs/heads/main/alink_install.sh</span></span>
<span class="line"><span>sudo chmod +x alink_install.sh</span></span>
<span class="line"><span>sudo ./alink_install.sh gs remove</span></span>
<span class="line"><span>sudo ./alink_install.sh gs install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Чекати завершення оновлення. Перезавнтажити VRX.</p><hr><h2 id="встановлення-adaptive-link-на-камери-runcam-wifi-link-v1-v2" tabindex="-1">Встановлення Adaptive-Link на камери Runcam Wifi Link V1/V2 <a class="header-anchor" href="#встановлення-adaptive-link-на-камери-runcam-wifi-link-v1-v2" aria-label="Permalink to &quot;Встановлення Adaptive-Link на камери Runcam Wifi Link V1/V2&quot;">​</a></h2><ol><li>Завантажити <strong><a href="https://github.com/OpenIPC/openipc-configurator" target="_blank" rel="noreferrer">Мультиконфігуратор</a></strong></li><li>Розпакувати в папку та запустити.</li><li>Підключитися до камери <code>192.168.1.10</code> (пароль <code>12345</code>).</li><li>Натиснути <strong>Connect</strong> (синій — камера пінгується), після конекта визначається тип камери, сенсор та Wi-Fi карта.</li><li>Перейти в <strong>Firmware → Runcam → Wifilink → fpv</strong> і натиснути <strong>Update</strong>.</li><li>Після оновлення:<br> Відкрити Telemetry → увімкнути UART0, додати Mavlink<br> Увімкнути Alink Drone → Enable<br></li></ol><p>Після конекту між камерой та радхою ви маєте побачити ось таке віконце <br><img src="`+n+`" alt="" width="400px"><br></p><div class="warning custom-block"><p class="custom-block-title">Увага!</p><p>Якщо його немає — <code>adaptive_link</code> НЕ працює.</p></div><p>Редагування на Air Unit файл конфигурацій нас цікавить тільки кілька значень.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> /etc/alink.conf</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Тут виставляємо що для нас важливіше RSSI чи SNR</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>snr</span></span>
<span class="line"><span>rssi_weight=0,5</span></span>
<span class="line"><span>snr_weight=0,5</span></span>
<span class="line"><span>osd_level=5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Тут ми якщо хочемо інформацію приховати від alinka (бітрейт, завантаження ЦП та іншу інформацію) або що не так багато займала використовуємо від 0 - 5 ліній інформації</p><hr><h2 id="примусове-включення-adaptive-link" tabindex="-1">Примусове включення Adaptive Link <a class="header-anchor" href="#примусове-включення-adaptive-link" aria-label="Permalink to &quot;Примусове включення Adaptive Link&quot;">​</a></h2><ol><li>Відкрити WinSCP.</li><li>Підключитися до камери через FTP/SSH.</li><li>Відкрити <code>/etc/rc.local</code> та вставити перед <code>exit</code>:</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>alink_drone &amp;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="4"><li>Для розгону CPU (опціонально): відкрити <code>/etc/rc.local</code> і додати:</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> performance</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/devices/system/cpu/cpu0/cpufreq/scaling_governor</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1200000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/devices/system/cpu/cpu0/cpufreq/policy0/scaling_min_freq</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1200000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/devices/system/cpu/cpu0/cpufreq/policy0/scaling_max_freq</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">Зверни увагу!</p><p><strong>Увага:</strong> деякі камери можуть нестабільно працювати з розгоном — протестуйте на стенді!</p></div><hr><h2 id="безпечні-tx‐профілі" tabindex="-1">Безпечні TX‑профілі <a class="header-anchor" href="#безпечні-tx‐профілі" aria-label="Permalink to &quot;Безпечні TX‑профілі&quot;">​</a></h2><p>txprofile для мережевих карток - <a href="https://github.com/OpenIPC/adaptive-link/tree/main/txprofiles" target="_blank" rel="noreferrer">тут</a> (<em>назва завжди повинна бути - txprofile.conf</em> )</p><p>Приклад безпечного TX‑профілю</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># &lt;ra - nge&gt; &lt;gi&gt; &lt;mcs&gt; &lt;fecK&gt; &lt;fecN&gt; &lt;bitrate&gt; &lt;gop&gt; &lt;Pwr&gt; &lt;roiQP&gt; &lt;bandwidth&gt; &lt;qpDelta&gt;</span></span>
<span class="line"><span>999 - 999   long 0 8 12 1999 10 30 0,0,0,0 20 -12</span></span>
<span class="line"><span>1000 - 1050 long 0 8 12 2000 10 30 0,0,0,0 20 -12</span></span>
<span class="line"><span>1051 - 1500 long 1 8 12 4000 10 25 0,0,0,0 20 -12</span></span>
<span class="line"><span>1501 - 1950 long 2 8 12 8000 10 20 12,6,6,12 20 -12</span></span>
<span class="line"><span>1951 - 2001 short 2 8 12 9000 10 20 12,6,6,12 20 -12</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><hr><h2 id="параметри-tx-фаилу" tabindex="-1">Параметри TX-файлу <a class="header-anchor" href="#параметри-tx-фаилу" aria-label="Permalink to &quot;Параметри TX-файлу&quot;">​</a></h2><ul><li><strong>range</strong> — діапазон для адаптивної передачі.</li><li><strong>gi</strong> — захисний інтервал.</li><li><strong>mcs</strong> — схема модуляції та кодування.</li><li><strong>fecK</strong> — кількість інформаційних символів у FEC.</li><li><strong>fecN</strong> — загальна кількість символів у FEC.</li><li><strong>bitrate</strong> — швидкість передачі даних (біт/с).</li><li><strong>gop</strong> — інтервал між ключовими кадрами.</li><li><strong>Pwr</strong> — рівень потужності передавача.</li><li><strong>roiQP</strong> — квантовування для зони інтересу.</li><li><strong>bandwidth</strong> — пропускна здатність каналу.</li><li><strong>qpDelta</strong> — коригувальна різниця для QP.</li></ul><hr>`,39)])])}const k=i(l,[["render",p]]);export{m as __pageData,k as default};
